/* eslint-disable @typescript-eslint/no-var-requires */
// Generated by Selenium IDE
// eslint-disable-next-line @typescript-eslint/no-var-requires
const { Builder, By, until } = require('selenium-webdriver');
const assert = require('assert');

describe('JP-text', function () {
  this.timeout(30000);
  let driver;
  let vars;
  beforeEach(async function () {
    driver = await new Builder().forBrowser('chrome').build();
    vars = {};
  });
  afterEach(async function () {
    await driver.quit();
  });
  it('JP-text', async function () {
    await driver.get('http://localhost:4200');
    await driver.manage().window().setRect({ width: 1360, height: 768 });
    await driver.findElement(By.id('login_form_email')).click();
    await driver.findElement(By.id('login_form_email')).sendKeys('vietnam.system');
    await driver.findElement(By.id('login_form_password')).click();
    await driver.findElement(By.id('login_form_password')).sendKeys('12345678');
    await driver.findElement(By.css('.ant-btn')).click();
    {
      const element = await driver.findElement(By.css('.ant-btn'));
      await driver.actions({ bridge: true }).moveToElement(element).perform();
    }
    {
      const element = await driver.findElement(By.CSS_SELECTOR, 'body');
      await driver.actions({ bridge: true }).moveToElement(element, 0, 0).perform();
    }
    await driver.findElement(By.css('.ant-row:nth-child(4) .ant-card-body')).click();
    await driver.wait(until.elementLocated(By.css('.ant-typography:nth-child(1)')), 100);
    await driver.findElement(By.xpath("//div[@id='root']/section/section/header/ul/li[2]/span")).click();
    await driver.findElement(By.name('Search')).click();
    {
      const element = await driver.findElement(By.name('Search'));
      await driver.actions({ bridge: true }).moveToElement(element).perform();
    }
    {
      const element = await driver.findElement(By.CSS_SELECTOR, 'body');
      await driver.actions({ bridge: true }).moveToElement(element, 0, 0).perform();
    }
    await driver
      .findElement(
        By.xpath("//div[@id='root']/section/section/main/div/div[2]/div/div/div/div/div/div/table/tbody/tr/td"),
      )
      .click();
    assert((await driver.findElement(By.xpath('//h3')).getText()) == '専門スキル詳細');
    assert(
      (await driver
        .findElement(By.xpath("//div[@id='root']/section/section/main/div/form/div/div/div/label"))
        .getText()) == '部署',
    );
    assert(
      (await driver
        .findElement(By.xpath("//div[@id='root']/section/section/main/div/form/div[2]/div/div/label"))
        .getText()) == 'バージョン',
    );
    assert(
      (await driver
        .findElement(By.xpath("//div[@id='root']/section/section/main/div/form/div[3]/div/div/label"))
        .getText()) == '状態',
    );
    assert(
      (await driver
        .findElement(By.xpath("//div[@id='root']/section/section/main/div/form/div[4]/div/div/label"))
        .getText()) == '公開ステータス',
    );
    assert(
      (await driver
        .findElement(By.xpath("//div[@id='root']/section/section/main/div/form/div[5]/div/div/label"))
        .getText()) == '最終更新者',
    );
    assert(
      (await driver
        .findElement(By.xpath("//div[@id='root']/section/section/main/div/form/div[6]/div/div/label"))
        .getText()) == '最終更新日',
    );
    assert(
      (await driver
        .findElement(By.xpath("//div[@id='root']/section/section/main/div/form/div[7]/div/div/label"))
        .getText()) == '公開日',
    );
    assert(
      (await driver.findElement(By.xpath("//div[@id='root']/section/section/main/div/div/h4")).getText()) ==
        '専門スキル評価項目一覧',
    );
    assert(
      (await driver
        .findElement(
          By.xpath("//div[@id='root']/section/section/main/div/div/div/div/div/div/div/div/table/thead/tr/th"),
        )
        .getText()) == '職種',
    );
    assert(
      (await driver
        .findElement(
          By.xpath("//div[@id='root']/section/section/main/div/div/div/div/div/div/div/div/table/thead/tr/th[2]"),
        )
        .getText()) == '大・中分類',
    );
    assert(
      (await driver
        .findElement(
          By.xpath("//div[@id='root']/section/section/main/div/div/div/div/div/div/div/div/table/thead/tr/th[3]"),
        )
        .getText()) == '小分類',
    );
    assert(
      (await driver
        .findElement(
          By.xpath("//div[@id='root']/section/section/main/div/div/div/div/div/div/div/div/table/thead/tr/th[4]"),
        )
        .getText()) == '評価内容',
    );
    assert(
      (await driver
        .findElement(
          By.xpath("//div[@id='root']/section/section/main/div/div/div/div/div/div/div/div/table/thead/tr/th[5]"),
        )
        .getText()) == '難易度',
    );
    assert(
      (await driver
        .findElement(
          By.xpath("//div[@id='root']/section/section/main/div/div/div/div/div/div/div/div/table/thead/tr/th[6]"),
        )
        .getText()) == '備考',
    );
    vars['button_color'] = await driver.executeScript(
      "return getComputedStyle(document.querySelector('#root > section > section > main > div > div > div.evaluation-sider > div > button'))['background-color']",
    );
    assert(vars['button_color'].toString() == 'rgb(0, 135, 77)');
    await driver.findElement(By.css('.anticon-logout > svg')).click();
    await driver.findElement(By.css('.ant-space-item > .ant-btn-primary > span')).click();
  });
});
